variables.openclawModelsJson:
[if(variables('hasAzureOpenAiConfig'), concat(',
', '  "models": {
', '    "mode": "merge",
', '    "providers": {
', '      "openai": {
', '        "baseUrl": "', variables('azureOpenAiBaseUrl'), '",
', '        "apiKey": "${OPENAI_API_KEY}",
', '        "api": "openai-responses",
', '        "models": [
', '          {
', '            "id": "', parameters('azureOpenAiDeployment'), '",
', '            "name": "Azure OpenAI ', parameters('azureOpenAiDeployment'), '",
', '            "reasoning": false,
', '            "input": ["text", "image"],
', '            "cost": { "input": 0, "output": 0, "cacheRead": 0, "cacheWrite": 0 },
', '            "contextWindow": 200000,
', '            "maxTokens": 16384
', '          }
', '        ]
', '      }
', '    }
', '  }'), '')]

variables.caddyConfig:
[concat(variables('caddySiteAddresses'), ' {
', '    encode zstd gzip
', '    handle ', variables('msteamsWebhookPath'), ' {
', '        reverse_proxy 127.0.0.1:', string(variables('msteamsPort')), '
', '    }
', '    reverse_proxy 127.0.0.1:', string(variables('openclawPort')), '
', '}
')]

variables.openclawConfig:
[concat('{
', '  "agents": {
', '    "defaults": {
', '      "workspace": "/data/workspace"', variables('openclawDefaultModelJson'), '
', '    }
', '  }', variables('openclawModelsJson'), variables('openclawChannelsOpen'), variables('openclawFeishuJson'), variables('openclawChannelSeparator'), variables('openclawMsTeamsJson'), variables('openclawChannelsClose'), ',
', '  "gateway": {
', '    "mode": "local",
', '    "bind": "loopback",
', '    "port": ', string(variables('openclawPort')), ',
', '    "controlUi": {
', '      "enabled": true,
', '      "allowedOrigins": ', variables('allowedOriginsJson'), '
', '    },
', '    "auth": {
', '      "mode": "token",
', '      "token": "${OPENCLAW_GATEWAY_TOKEN}"
', '    }
', '  }
', '}')]
